    const H = parseInt(parts[0], 10);
    const W = parseInt(parts[1], 10);

    const grid: string[] = [];
    let lineIdx = 1;
    for (let i = 0; i < H; i++) {
        while (lineIdx < input.length && input[lineIdx].trim() === '') {
            lineIdx++;
        }
        grid.push(input[lineIdx].trim());
        lineIdx++;
    }

    let startR = -1, startC = -1, targetR = -1, targetC = -1;
    for (let r = 0; r < H; r++) {
        for (let c = 0; c < W; c++) {
            const ch = grid[r][c];
            if (ch === 'S') {
                startR = r; startC = c;
            } else if (ch === 'T') {
                targetR = r; targetC = c;
            }
        }
    }

    const INF = Number.MAX_SAFE_INTEGER;
    const dist: number[][] = Array.from({length: H}, () => new Array(W).fill(INF));
    dist[startR][startC] = 0;

    const heap = new MinHeap();
    heap.push([0, startR, startC]);

    const dr = [-1, 1, 0, 0];
    const dc = [0, 0, -1, 1];

    while (!heap.isEmpty()) {
        const [cost, r, c] = heap.pop();
        if (cost > dist[r][c]) continue;
        if (r === targetR && c === targetC) {
            console.log(cost);
            return;
        }
        for (let d = 0; d < 4; d++) {
            const nr = r + dr[d];
            const nc = c + dc[d];
            if (nr < 0 || nr >= H || nc < 0 || nc >= W) continue;
            const ch = grid[nr][nc];
            if (ch === '#') continue;
            const cellCost = (ch >= '0' && ch <= '9') ? parseInt(ch, 10) : 0;
            const newCost = cost + cellCost;
            if (newCost < dist[nr][nc]) {
                dist[nr][nc] = newCost;
                heap.push([newCost, nr, nc]);
            }
        }
    }

    console.log(-1);
}

class MinHeap {
    private heap: [number, number, number][];

    constructor() {
        this.heap = [];
